class Solution:
    def dailyTemperatures(self, temperatures: list[int]) -> list[int]:
        i = 0
        stack = []
        answer = []
        while i < len(temperatures):
            if stack and stack[0]<temperatures[i]:
                i = i - len(stack) + 1
                answer.append(len(stack))
                stack = []
            stack.append(temperatures[i])
            if stack and i == len(temperatures) - 1:
                answer.append(0) 
                i = i-len(stack) + 1
                stack = []
            i+=1
        return answer

